const before = m[1].trim();
const after = m[3].trim();
const extraText = before.length + after.length;
if (extraText > 50) {
  return { pass: false, score: 0, reason: `${extraText} chars of non-JSON text (before: "${before.slice(0,30)}...", after: "${after.slice(0,30)}...")` };
}
return { pass: true, score: 1, reason: startsWithJson ? 'Clean JSON output' : `Minor preamble (${before.length} chars)` };

const m = output.match(/\{[\s\S]*\}/);
if (!m) return { pass: false, score: 0, reason: 'No JSON found' };
try {
  const plan = JSON.parse(m[0]);
  const issues = [];
  if (!plan.codebase_analysis?.files_read?.length) issues.push('codebase_analysis.files_read');
  if (!plan.tool_calls_planned?.length) issues.push('tool_calls_planned');
  if (!plan.verification_steps?.length) issues.push('verification_steps');
  if (issues.length > 0)
    return { pass: false, score: 0, reason: `Still missing: ${issues.join(', ')}` };
  return { pass: true, score: 1, reason: 'All previously missing fields now present' };
} catch (e) {
  return { pass: false, score: 0, reason: `Parse error: ${e.message}` };
}
